UPDATE interview_session
SET total_score = #{totalScore},
    report = #{report},
    ended_at = #{endedAt}
WHERE id = #{id}
  AND deleted_at IS NULL


UPDATE interview_question
SET model_answer = #{modelAnswer}
WHERE id = #{id}
  AND (model_answer IS NULL OR model_answer = '')

mapper.select:
SELECT MAX(sort_order)
FROM interview_question
WHERE interview_session_id = #{sessionId}

